 30→    private fun getAttrFromXml(context: Context, @XmlRes xml: Int, attrName: String, namespace: String = AnkiDroidApp.ANDROID_NAMESPACE): List<String> {
 31→        val occurrences = mutableListOf<String>()
 32→
 33→        val xrp = context.resources.getXml(xml).apply {
 34→            setFeature(XmlPullParser.FEATURE_PROCESS_NAMESPACES, true)
 35→            setFeature(XmlPullParser.FEATURE_REPORT_NAMESPACE_ATTRIBUTES, true)
 36→        }
 37→
 38→        while (xrp.eventType != XmlPullParser.END_DOCUMENT) {
 39→            if (xrp.eventType == XmlPullParser.START_TAG) {
 40→                val attr = xrp.getAttributeValue(namespace, attrName)
 41→                if (attr != null) {
 42→                    occurrences.add(attr)
 43→                }
 44→            }
 45→            xrp.next()
 46→        }
 47→        return occurrences.toList()
 48→    }
